sys_script.script:
(function executeRule(current, previous ) {

    var parent_sysId = '';
    var helpDeskTask = new GlideRecord(current.table_name);
    helpDeskTask.get(current.table_sys_id);
    if (helpDeskTask) {
        parent_sysId = helpDeskTask.parent;
    }
    if (current.operation() == "insert") {
        var att = new GlideRecord('sys_attachment');
        att.initialize();
        att.file_name = current.file_name;
        att.content_type = current.content_type;
        att.compressed = current.compressed;
        att.table_name = 'x_nainr_onenav_pro_help_desk_request';
        att.size_bytes = current.size_bytes;
        att.size_compressed = current.size_compressed;
        att.table_sys_id = parent_sysId;
        att.chunk_size_bytes = current.chunk_size_bytes;
        att.image_height = current.image_height;
        att.image_width = current.image_width;
        var attRec = att.insert();
        var attDoc = new GlideRecord('sys_attachment_doc');
        attDoc.addQuery('sys_attachment', current.sys_id);
        attDoc.query();
        if (attDoc.next()) {
            var attDocCopy = new GlideRecord('sys_attachment_doc');
            attDocCopy.initialize();
            attDocCopy.sys_attachment = attRec;
            attDocCopy.position = attDoc.position;
            attDocCopy.length = attDoc.length;
            attDocCopy.data = attDoc.data;
            var attachCopy = attDocCopy.insert();
        }
    } else {
        var del_att = new GlideRecord('sys_attachment');
        del_att.addQuery('file_name', current.file_name);
        del_att.addQuery('content_type', current.content_type);
        del_att.addQuery('table_name', 'x_nainr_onenav_pro_help_desk_request');
        del_att.addQuery('size_bytes', current.size_bytes);
        del_att.addQuery('table_sys_id', parent_sysId);
        del_att.query();
        if (del_att.next()) {
            var attachment = new GlideSysAttachment();
            attachment.deleteAttachment(del_att.getValue('sys_id'));
        }
    }
})(current, previous);
